export const 衝命玉符二 = (bi) => {
    const u = bi.u, k = 1.8;
    const X = (c) => (c - 4.9) * k;
    const Z = (r) => (r - 1.4) * k + 2;
    const 抖 = (書, 寬 = 0.66) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    bi.硃(() => {
        // 左柱：密蟠切返四疊，下曳長尾
        抖(p => p.M(X(1.6), Z(2.1))
            .C(X(2.4), Z(2.4), X(3.2), Z(2.7), X(3.4), Z(3.4))
            .C(X(3.6), Z(4.1), X(2.4), Z(4.0), X(1.7), Z(4.4))
            .C(X(1.1), Z(4.8), X(1.5), Z(5.4), X(2.6), Z(5.4))
            .C(X(3.6), Z(5.4), X(3.9), Z(6.0), X(3.2), Z(6.5))
            .C(X(2.4), Z(7.0), X(1.4), Z(6.9), X(1.5), Z(7.5))
            .C(X(1.6), Z(8.1), X(2.4), Z(8.3), X(2.7), Z(8.9))
            .C(X(3.0), Z(9.8), X(2.9), Z(10.8), X(3.1), Z(11.7))
            .C(X(3.3), Z(12.6), X(2.9), Z(13.4), X(2.2), Z(13.9))
            .C(X(1.9), Z(14.1), X(1.8), Z(14.3), X(1.8), Z(14.4)), 0.7);
        // 左旁短劃
        抖(p => p.M(X(1.5), Z(9.1)).C(X(1.4), Z(9.9), X(1.4), Z(10.6), X(1.5), Z(11.2)), 0.56);
        // 中柱：緩S長垂左掃
        抖(p => p.M(X(4.7), Z(1.8))
            .C(X(5.3), Z(2.3), X(5.5), Z(2.9), X(5.2), Z(3.5)), 0.62);
        抖(p => p.M(X(5.3), Z(4.4))
            .C(X(5.7), Z(5.3), X(5.2), Z(6.2), X(5.1), Z(7.1))
            .C(X(5.0), Z(8.0), X(5.5), Z(8.8), X(5.2), Z(9.7))
            .C(X(4.9), Z(10.7), X(4.5), Z(11.6), X(4.3), Z(12.5))
            .C(X(4.1), Z(13.3), X(3.8), Z(13.9), X(3.5), Z(14.3)), 0.66);
        // 右柱：環首・S折・綴點・鉤尾
        抖(p => p.M(X(6.7), Z(2.4))
            .C(X(7.1), Z(1.9), X(7.8), Z(1.7), X(8.2), Z(2.1))
            .C(X(8.6), Z(2.5), X(8.3), Z(3.0), X(7.7), Z(3.1)), 0.64);
        抖(p => p.M(X(7.1), Z(3.7))
            .C(X(7.6), Z(4.5), X(7.4), Z(5.5), X(6.6), Z(6.2))
            .C(X(6.0), Z(6.8), X(6.2), Z(7.6), X(7.0), Z(8.0))
            .C(X(7.5), Z(8.3), X(7.5), Z(9.1), X(7.0), Z(9.8))
            .C(X(6.7), Z(10.3), X(6.9), Z(10.9), X(7.4), Z(11.2)), 0.66);
        bi.dot(X(6.6), Z(11.5), 0.3);
        抖(p => p.M(X(6.3), Z(11.8))
            .C(X(6.8), Z(12.3), X(7.2), Z(12.8), X(7.4), Z(13.4))
            .C(X(7.6), Z(13.9), X(7.7), Z(14.3), X(7.8), Z(14.6)), 0.64);
    });
};
